// Copy the repo's generated client + API types into this package's src so the
// published @jsonbored/metagraphed always tracks the live OpenAPI contract. The
// generated files are committed at the repo root (regenerated by `npm run
// build`), so this is a pure copy — no network or codegen here.
import { promises as fs } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const here = path.dirname(fileURLToPath(import.meta.url));
const packageRoot = path.resolve(here, "..");
const repoRoot = path.resolve(packageRoot, "..", "..");
const srcDir = path.join(packageRoot, "src");

// Copy the API types as `.ts` (not `.d.ts`) so the bundler emits proper
// declarations; the client's `import type` of these is erased at runtime.
const copies = [
  ["generated/metagraphed-api.d.ts", "metagraphed-api.ts"],
  ["generated/metagraphed-client.ts", "metagraphed-client.ts"],
];

await fs.mkdir(srcDir, { recursive: true });
for (const [from, to] of copies) {
  const source = path.join(repoRoot, from);
  const content = await fs.readFile(source, "utf8");
  await fs.writeFile(path.join(srcDir, to), content, "utf8");
}
console.log(
  `Synced ${copies.length} generated file(s) into packages/client/src.`,
);
